sql:
SELECT category_id, COUNT(data_id) AS dataset_count, AVG(thickness) AS average_thickness
FROM geological_data
GROUP BY category_id;

SELECT COUNT(DISTINCT data_id) AS unique_sedimentary_formations
FROM geological_data
WHERE category_id = 1;

SELECT data_id, depth
FROM geological_data
ORDER BY depth DESC;

SELECT DISTINCT s.site_name
FROM sites s
JOIN geological_data gd ON s.site_id = gd.site_id;

SELECT DISTINCT site_name
FROM sites
INNER JOIN geological_data ON sites.site_id = geological_data.site_id;

SELECT site_type, COUNT(site_id) AS number_of_sites
FROM sites
GROUP BY site_type;

SELECT count(*) AS total_locations
FROM sites
WHERE site_type = 'geological';

SELECT DISTINCT s.site_name
FROM geological_data g
JOIN sites s ON g.site_id = s.site_id;

external_knowledge:
- The term "most documented" refers to the category with the highest number of datasets; 
- "Records" in this context refer to the entries or rows in the geological data table;
- The order "from the most documented to the least" implies sorting the categories based on the count of their records in descending order.
